import{_ as o,H as a,f as t,i as n}from"./chunks/framework.DbTCwA-u.js";const h=JSON.parse('{"title":"Устранение неполадок","description":"Частые проблемы и их решения при использовании EligiusNametag.","frontmatter":{"title":"Устранение неполадок","description":"Частые проблемы и их решения при использовании EligiusNametag."},"headers":[],"relativePath":"ru/troubleshooting.md","filePath":"ru/troubleshooting.md"}'),r={name:"ru/troubleshooting.md"};function i(l,e,s,c,d,u){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="устранение-неполадок-troubleshooting" tabindex="-1">Устранение неполадок (Troubleshooting) <a class="header-anchor" href="#устранение-неполадок-troubleshooting" aria-label="Permalink to &quot;Устранение неполадок (Troubleshooting)&quot;">​</a></h1><p>Возникли проблемы с EligiusNametag? Проверьте эти распространенные решения:</p><h3 id="_1-неимтег-не-появляется-над-игроком" tabindex="-1">1. Неймтег не появляется над игроком <a class="header-anchor" href="#_1-неимтег-не-появляется-над-игроком" aria-label="Permalink to &quot;1. Неймтег не появляется над игроком&quot;">​</a></h3><ul><li><strong>Установлен ли ProtocolLib?</strong> Наш плагин строго зависит от инъекции пакетов, чтобы неймтеги плавно парили, не вызывая лагов.</li><li><strong>Установлен ли PlaceholderAPI?</strong> Если вы используете переменные вроде <code>%vault_rank%</code> и у вас нет PAPI, текст может не отображаться.</li></ul><h3 id="_2-ошибка-database-connection-closed" tabindex="-1">2. Ошибка &quot;Database Connection Closed&quot; <a class="header-anchor" href="#_2-ошибка-database-connection-closed" aria-label="Permalink to &quot;2. Ошибка &quot;Database Connection Closed&quot;&quot;">​</a></h3><ul><li>Эта проблема <strong>исправлена в последних версиях</strong>. Убедитесь, что вы используете последнюю версию <code>v1.x.x</code> или выше. Если вы используете <strong>MySQL</strong>, проверьте правильность IP-адреса и учетных данных в <code>config.yml</code>. В противном случае используйте локальный <code>SQLITE</code>.</li></ul><h3 id="_3-предупреждения-viaversion-в-консоли" tabindex="-1">3. Предупреждения ViaVersion в консоли <a class="header-anchor" href="#_3-предупреждения-viaversion-в-консоли" aria-label="Permalink to &quot;3. Предупреждения ViaVersion в консоли&quot;">​</a></h3><p>Если вы используете ViaVersion, чтобы разрешить игрокам с версии 1.20 заходить на ваш сервер 1.21+, вы можете увидеть сообщения о <em>Metadata</em> и <em>Protocol Versions</em>.</p><ul><li><strong>Причина:</strong> Старый клиент (например, 1.20.2) не имеет встроенного кода для правильной обработки крупных сущностей <code>TEXT_DISPLAY</code>.</li><li><strong>Решение:</strong> Мы настоятельно рекомендуем требовать версии 1.21+ для идеального отображения голограмм, или просто игнорируйте предупреждение, если у игрока не возникает визуальных сбоев.</li></ul><h3 id="_4-enametag-lang-не-обновляет-сообщение-помощи" tabindex="-1">4. /enametag lang не обновляет сообщение помощи <a class="header-anchor" href="#_4-enametag-lang-не-обновляет-сообщение-помощи" aria-label="Permalink to &quot;4. /enametag lang не обновляет сообщение помощи&quot;">​</a></h3><p>При использовании <code>/enametag lang ru</code> плагин читает из <code>lang/ru.yml</code>. Если вы заметили, что какой-то перевод пуст или команда ведет себя странно, вы можете удалить папку <code>lang/</code> в каталоге плагинов, чтобы EligiusNametag мог заново сгенерировать её с последними стандартами.</p>',11)])])}const _=o(r,[["render",i]]);export{h as __pageData,_ as default};
